module top_module(
    ERR_CLOCK,
    RESET,
    x,
    y,
    DIFF
);input ERR_CLOCK, RESET;
    input [11:0] x, y;
    output reg [11:0] DIFF;

    always @ (posedge ERR_CLOCK or posedge RESET) begin
        if (RESET) begin
            DIFF <= 0;
        end else begin
            DIFF <= (x > y) ? x - y : y - x;
        end
    end

endmodule
